"""The high-level compare() API and the verdict -is your improvement real, or noise?"""
from __future__ import annotations

from dataclasses import asdict, dataclass

import numpy as np

from .corrections import bonferroni
from .stats import (
    bootstrap_diff_ci,
    fwer,
    mcnemar_counts,
    mcnemar_exact,
    paired_permutation_test,
    required_n,
)


@dataclass
class ComparisonResult:
    n: int
    baseline_mean: float
    candidate_mean: float
    effect: float                 # candidate - baseline (in score points, e.g. 0.04 = +4pp)
    test: str                     # 'mcnemar_exact' or 'paired_permutation'
    binary: bool
    p_value: float                # raw paired p-value
    variants_tried: int
    p_adjusted: float             # after the variants-tried (Bonferroni) correction
    alpha: float
    ci: tuple                     # (lo, hi) CI on the effect
    ci_level: float
    significant: bool             # adjusted AND a genuine improvement (effect > 0)
    verdict: str
    recommendation: str
    fwer_at_variants: float       # P(>=1 false win) across the declared variants, at alpha
    b01: int = 0                  # improvements (baseline wrong -> candidate right)
    b10: int = 0                  # regressions (baseline right -> candidate wrong)
    suggested_n: int | None = None  # tasks needed to call THIS effect real, if not significant

    def to_dict(self) -> dict:
        d = asdict(self)
        d["ci"] = list(self.ci)
        return d

    def report(self) -> str:
        pp = lambda x: f"{x * 100:+.1f} pts"
        lo, hi = self.ci
        mark = "PASS" if self.significant else "FAIL"
        lines = [
            f"  Holdout - significance check                                  [{mark}]",
            f"  baseline {self.baseline_mean * 100:.1f}%  ->  candidate {self.candidate_mean * 100:.1f}%   "
            f"(n = {self.n} tasks)",
            f"  effect          {pp(self.effect)}        95% CI [{lo * 100:+.1f}, {hi * 100:+.1f}]",
            f"  test            {self.test}   p = {self.p_value:.3f}",
            f"  variants tried  {self.variants_tried}   ->  adjusted p = {self.p_adjusted:.3f}"
            + (f"   (any-false-win risk {self.fwer_at_variants * 100:.0f}%)"
               if self.variants_tried > 1 else ""),
        ]
        if self.binary:
            lines.append(f"  paired counts   +{self.b01} fixed / -{self.b10} broke "
                         f"(net {self.b01 - self.b10:+d})")
        lines.append("")
        lines.append(f"  VERDICT: {self.verdict}")
        lines.append(f"  -> {self.recommendation}")
        return "\n".join(lines)


def _is_binary(arr) -> bool:
    u = np.unique(np.asarray(arr, dtype=float))
    return bool(np.all(np.isin(u, [0.0, 1.0])))


def compare(baseline_scores, candidate_scores, *, variants_tried: int = 1, alpha: float = 0.05,
            ci_level: float = 0.95, n_resamples: int = 10000, seed: int = 0,
            test: str = "auto") -> ComparisonResult:
    """Paired comparison of two systems scored on the SAME ordered task set.

    baseline_scores / candidate_scores: aligned per-task scores (0/1 for pass-fail, or floats).
    variants_tried: how many variants you tried before reporting this one (raises the bar).
    """
    a = np.asarray(baseline_scores, dtype=float)
    b = np.asarray(candidate_scores, dtype=float)
    if a.shape != b.shape:
        raise ValueError(f"baseline and candidate must be the same length (paired): "
                         f"{a.shape} vs {b.shape}")
    if a.size == 0:
        raise ValueError("no tasks to compare")

    binary = _is_binary(a) and _is_binary(b)
    diffs = b - a
    n = int(a.size)
    baseline_mean = float(a.mean())
    candidate_mean = float(b.mean())
    effect = float(diffs.mean())

    b01, b10 = mcnemar_counts(a, b) if binary else (0, 0)

    use = test
    if use == "auto":
        use = "mcnemar_exact" if binary else "paired_permutation"

    if use == "mcnemar_exact":
        if not binary:
            raise ValueError("mcnemar_exact requires binary (0/1) scores")
        p_value = mcnemar_exact(b01, b10)
    elif use == "paired_permutation":
        _, p_value = paired_permutation_test(diffs, n_resamples=n_resamples, seed=seed)
    else:
        raise ValueError(f"unknown test: {test}")

    ci = bootstrap_diff_ci(diffs, ci=ci_level, n_resamples=n_resamples, seed=seed)
    p_adjusted = bonferroni(p_value, variants_tried)
    significant = (p_adjusted < alpha) and (effect > 0)
    fwer_at = fwer(variants_tried, alpha)

    suggested_n = None
    if effect > 0 and not significant:
        suggested_n = required_n(effect, baseline_acc=baseline_mean, alpha=alpha)

    verdict, rec = _verdict(effect, p_value, p_adjusted, alpha, variants_tried, suggested_n)

    return ComparisonResult(
        n=n, baseline_mean=baseline_mean, candidate_mean=candidate_mean, effect=effect,
        test=use, binary=binary, p_value=p_value, variants_tried=int(variants_tried),
        p_adjusted=p_adjusted, alpha=alpha, ci=ci, ci_level=ci_level,
        significant=significant, verdict=verdict, recommendation=rec,
        fwer_at_variants=fwer_at, b01=b01, b10=b10, suggested_n=suggested_n,
    )


def _verdict(effect, p_value, p_adjusted, alpha, variants_tried, suggested_n):
    if effect <= 0:
        if p_adjusted < alpha:
            return ("REGRESSION - candidate is significantly worse.",
                    "Do not ship. The candidate is a real step backwards.")
        return ("No improvement - within noise.",
                "Nothing to ship; the candidate is not better than the baseline.")
    if p_adjusted < alpha:
        return ("REAL IMPROVEMENT - significant after correction.",
                "Ship it. The gain survives a paired test and the variants-tried bar.")
    if p_value < alpha <= p_adjusted:
        return ("WITHIN NOISE after variants - likely a multiple-comparisons artifact.",
                f"Don't ship on this alone: significant raw, but you tried {variants_tried} "
                f"variants - the best of that many is expected to look like a win. "
                f"Confirm on a fresh held-out set.")
    tail = f" You'd need ~{suggested_n} tasks for an effect this size to be detectable." \
        if suggested_n else ""
    return ("WITHIN NOISE - not statistically significant.",
            f"Don't ship on this alone; the gain is indistinguishable from sampling noise.{tail}")
